// Creates a new W&B Metrics API client
export const createClient = () => new WandbMetricsClient()

// A summary of an experiment run
export interface RunSummary {
  id: string
  name: string
  status: "running" | "finished" | "failed"
  createdAt: string
  tags: string[]
  summary: {
    accuracy: number
    loss: number
    epochs: number
    trainingTime: number // seconds
  }
}

// A single data point in a metric time-series
export interface MetricPoint {
  step: number
  value: number
  timestamp: string
}

class WandbMetricsClient {
  /**
   * List experiment runs with cursor-based pagination.
   *
   * @param options.projectId - The project to list runs for
   * @param options.cursor - Opaque cursor token for the next page (omit for first page)
   * @param options.limit - Max runs per page (default 5, max 10)
   * @returns Paginated result with runs, nextCursor, and totalCount
   */
  public async listRuns(options: {
    projectId: string
    cursor?: string
    limit?: number
  }): Promise<{ runs: RunSummary[]; nextCursor: string | undefined; totalCount: number }> {
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        if (!options.projectId) {
          reject(new Error("projectId is required"))
          return
        }

        const allRuns = projectRuns[options.projectId]
        if (!allRuns) {
          resolve({ runs: [], nextCursor: undefined, totalCount: 0 })
          return
        }

        const limit = Math.min(options.limit || 5, 10)
        const startIndex = options.cursor ? parseInt(options.cursor, 10) : 0

        if (isNaN(startIndex)) {
          reject(new Error("Invalid cursor"))
          return
        }

        const endIndex = startIndex + limit
        const runs = allRuns.slice(startIndex, endIndex)
        const nextCursor = endIndex < allRuns.length ? String(endIndex) : undefined

        resolve({
          runs: runs.map(r => ({ ...r })),
          nextCursor,
          totalCount: allRuns.length,
        })
      }, 80 + Math.random() * 120)
    })
  }

  /**
   * Get the full metric time-series for a given run and metric name.
   *
   * @param runId - The run ID
   * @param metricName - The metric name ("accuracy" or "loss")
   * @returns Array of MetricPoint in step order
   */
  public async getMetricHistory(
    runId: string,
    metricName: string
  ): Promise<MetricPoint[]> {
    return new Promise((resolve) => {
      setTimeout(() => {
        const key = `${runId}:${metricName}`
        const history = metricHistories[key]
        resolve(history ? [...history] : [])
      }, 80 + Math.random() * 80)
    })
  }
}

// Helper to generate metric history
function generateMetricHistory(
  runId: string,
  metricName: string,
  steps: number,
  startValue: number,
  trend: "up" | "down",
  noise: number
): MetricPoint[] {
  const points: MetricPoint[] = []
  let value = startValue
  const baseDate = new Date("2025-03-01T10:00:00Z")

  for (let step = 0; step < steps; step++) {
    const delta = trend === "up"
      ? (Math.random() * 0.02 + 0.005)
      : -(Math.random() * 0.02 + 0.005)
    value = Math.max(0, Math.min(1, value + delta + (Math.random() - 0.5) * noise))

    points.push({
      step,
      value: parseFloat(value.toFixed(4)),
      timestamp: new Date(baseDate.getTime() + step * 60000).toISOString(),
    })
  }
  return points
}

