const projectRuns: Record<string, RunSummary[]> = {
  "llm-finetune": llmFinetune,
  "image-classifier": imageClassifier,
}

// Pre-generate metric histories for some runs
const metricHistories: Record<string, MetricPoint[]> = {}

// LLM runs — accuracy goes up, loss goes down
for (const run of llmFinetune) {
  const steps = run.summary.epochs * 3 // ~3 steps per epoch
  metricHistories[`${run.id}:accuracy`] = generateMetricHistory(run.id, "accuracy", steps, 0.3, "up", 0.01)
  metricHistories[`${run.id}:loss`] = generateMetricHistory(run.id, "loss", steps, 2.5, "down", 0.05)
}

// Image classifier runs
